const data = $input.first().json;
const candidate = data.deepCandidate ?? null;
const repoUrl = candidate?.repositoryUrl ?? candidate?.sourceUrls?.find((url) => String(url).includes('github.com')) ?? null;
const match = typeof repoUrl === 'string' ? repoUrl.match(/github\.com\/([^/]+)\/([^/#?]+)/i) : null;
const repoSlug = match ? (match[1] + '/' + match[2]).replace(/\.git$/i, '') : null;
const github = repoSlug ? { owner: repoSlug.split('/')[0], repo: repoSlug.split('/')[1], repoSlug } : null;
const cleanVersion = (value) => {
  if (!value) return null;
  const versionMatch = String(value).match(/(\d+\.\d+\.\d+(?:[-+][0-9A-Za-z.-]+)?)/);
  return versionMatch ? versionMatch[1] : null;
};
return [{ json: { ...data, deepCandidate: candidate, repoUrl, github, npmUrl: candidate ? ('https://www.npmjs.com/package/' + candidate.name) : null, currentVersionClean: candidate ? cleanVersion(candidate.currentVersion) : null, latestVersionClean: candidate ? cleanVersion(candidate.latestVersion) : null, skipResearch: Boolean(data.skipResearch || !candidate) } }];

const context = $('Normalize package context').first().json;
const contents = Array.isArray($input.first().json) ? $input.first().json : [];
const classify = (entry) => {
  const fileName = String(entry?.name ?? '').toLowerCase();
  if (!fileName || !entry?.url) return null;
  if (fileName.includes('migration') || fileName.includes('upgrade')) return { name: entry.name, path: entry.path, apiUrl: entry.url, downloadUrl: entry.download_url ?? null, htmlUrl: entry.html_url ?? entry.download_url ?? context.repoUrl, label: 'migration-guide', priority: 1 };
  if (fileName.includes('changelog') || fileName === 'changes.md' || fileName === 'history.md' || fileName.includes('release-notes')) return { name: entry.name, path: entry.path, apiUrl: entry.url, downloadUrl: entry.download_url ?? null, htmlUrl: entry.html_url ?? entry.download_url ?? context.repoUrl, label: 'changelog', priority: 2 };
  if (fileName === 'readme.md') return { name: entry.name, path: entry.path, apiUrl: entry.url, downloadUrl: entry.download_url ?? null, htmlUrl: entry.html_url ?? entry.download_url ?? context.repoUrl, label: 'docs', priority: 3 };
  return null;
};
const docCandidates = contents.map(classify).filter(Boolean).sort((left, right) => left.priority - right.priority || left.name.localeCompare(right.name));
return [{ json: { ...context, docCandidates: docCandidates.slice(0, 3), primaryDocTarget: docCandidates[0] ?? null } }];

const getFirstJson = (name, fallback) => {
  try {
    return $(name).first()?.json ?? fallback;
  } catch (error) {
    return fallback;
  }
};
const context = $('Normalize package context').first().json;
const npm = getFirstJson('npm registry metadata', {});
const releases = getFirstJson('GitHub releases', []);
const docSelection = getFirstJson('Select documentation target', {});
const docPayload = getFirstJson('GitHub documentation raw', null);
const candidate = context.deepCandidate;
if (context.skipResearch || !candidate) {
  return [{ json: { ...context, canonicalEvidence: [], canonicalEvidenceStatus: 'none', needsFallback: true } }];
}
const cleanVersion = (value) => {
  if (!value) return null;
  const versionMatch = String(value).match(/(\d+\.\d+\.\d+(?:[-+][0-9A-Za-z.-]+)?)/);
  return versionMatch ? versionMatch[1] : null;
};
const parseSemver = (value) => {
  const cleaned = cleanVersion(value);
  if (!cleaned) return null;
  const match = cleaned.match(/^(\d+)\.(\d+)\.(\d+)/);
  if (!match) return null;
  return { raw: cleaned, major: Number(match[1]), minor: Number(match[2]), patch: Number(match[3]) };
};
const compareSemver = (left, right) => {
  if (!left || !right) return 0;
  if (left.major !== right.major) return left.major - right.major;
  if (left.minor !== right.minor) return left.minor - right.minor;
  return left.patch - right.patch;
};
const pickDocExcerpt = (text, versions) => {
  const source = String(text ?? '').replace(/\r/g, '');
  if (!source.trim()) return '';
  const needles = versions.filter(Boolean).flatMap((value) => [value, 'v' + value, '[' + value + ']']).map((value) => String(value).toLowerCase());
  const haystack = source.toLowerCase();
  let index = -1;
  for (const needle of needles) {
    const found = haystack.indexOf(needle);
    if (found >= 0) {
      index = found;
      break;
    }
  }
  if (index < 0) return source.slice(0, 1400);
  const start = Math.max(0, index - 220);
  return source.slice(start, start + 1400);
};
const decodeDocContent = (payload) => {
  if (!payload) return '';
  if (typeof payload === 'string') return payload;
  if (typeof payload.content === 'string') {
    if (payload.encoding === 'base64') {
      try {
        return Buffer.from(payload.content.replace(/\n/g, ''), 'base64').toString('utf8');
      } catch (error) {
        return '';
      }
    }
    return payload.content;
  }
  return '';
};
const currentPublishedAt = context.currentVersionClean && npm?.time?.[context.currentVersionClean] ? npm.time[context.currentVersionClean] : null;
const latestPublishedAt = context.latestVersionClean && npm?.time?.[context.latestVersionClean] ? npm.time[context.latestVersionClean] : null;
const metadataBits = [
  'Current ' + candidate.currentVersion,
  'latest ' + candidate.latestVersion,
  'diff ' + candidate.diffType,
  'deprecated ' + candidate.deprecated,
  currentPublishedAt ? ('current published ' + currentPublishedAt) : null,
  latestPublishedAt ? ('latest published ' + latestPublishedAt) : null,
  npm?.['dist-tags']?.latest ? ('dist-tag latest ' + npm['dist-tags'].latest) : null
].filter(Boolean).join('; ');
const evidence = [{ packageName: candidate.name, label: 'npm', url: context.npmUrl, title: 'npm metadata', excerpt: metadataBits, confidence: 'high' }];
let deprecatedMessage = null;
for (const key of [context.latestVersionClean, candidate.latestVersion, context.currentVersionClean, candidate.currentVersion]) {
  if (key && npm?.versions?.[key]?.deprecated) {
    deprecatedMessage = npm.versions[key].deprecated;
    break;
  }
}
if (deprecatedMessage || candidate.deprecated) {
  evidence.push({ packageName: candidate.name, label: 'npm', url: context.npmUrl, title: 'deprecation notice', excerpt: String(deprecatedMessage ?? 'npm y el analisis base marcan este paquete como deprecated.'), confidence: 'high' });
}
const currentParsed = parseSemver(context.currentVersionClean ?? candidate.currentVersion);
const latestParsed = parseSemver(context.latestVersionClean ?? candidate.latestVersion);
const releaseList = Array.isArray(releases) ? releases : [];
const relevantReleases = releaseList.filter((release) => {
  const parsed = parseSemver(String(release?.tag_name ?? release?.name ?? ''));
  if (!parsed) return false;
  if (latestParsed && compareSemver(parsed, latestParsed) > 0) return false;
  if (currentParsed && compareSemver(parsed, currentParsed) <= 0) return false;
  return true;
});
const selectedReleases = (relevantReleases.length ? relevantReleases : releaseList).slice(0, 4);
for (const release of selectedReleases) {
  const body = String(release?.body ?? '').trim();
  if (body.length < 40) continue;
  evidence.push({ packageName: candidate.name, label: 'github-release', url: release.html_url ?? context.repoUrl ?? context.npmUrl, title: release.name ?? release.tag_name ?? 'release', excerpt: body.slice(0, 1400), publishedAt: release.published_at ?? null, confidence: 'high' });
}
const primaryDocTarget = docSelection.primaryDocTarget ?? null;
const docContent = decodeDocContent(docPayload);
if (primaryDocTarget && docContent.trim()) {
  evidence.push({ packageName: candidate.name, label: primaryDocTarget.label, url: primaryDocTarget.htmlUrl ?? primaryDocTarget.downloadUrl ?? context.repoUrl ?? context.npmUrl, title: primaryDocTarget.name, excerpt: pickDocExcerpt(docContent, [context.latestVersionClean, context.currentVersionClean]), confidence: primaryDocTarget.label === 'docs' ? 'medium' : 'high' });
} else if (!selectedReleases.length && typeof npm?.readme === 'string' && npm.readme.trim()) {
  evidence.push({ packageName: candidate.name, label: 'docs', url: context.npmUrl, title: 'README from npm registry', excerpt: pickDocExcerpt(npm.readme, [context.latestVersionClean, context.currentVersionClean]), confidence: 'medium' });
}
const verifiedCanonicalEvidence = evidence.filter((entry) => {
  if (entry.label === 'npm' && entry.title === 'deprecation notice') return true;
  if (!['github-release', 'changelog', 'migration-guide'].includes(entry.label)) return false;
  return String(entry.excerpt ?? '').trim().length >= 80;
});
const canonicalEvidenceStatus = verifiedCanonicalEvidence.length ? 'verified' : evidence.length ? 'partial' : 'none';
return [{ json: { ...context, canonicalEvidence: evidence.slice(0, 8), canonicalEvidenceStatus, needsFallback: verifiedCanonicalEvidence.length === 0, primaryDocTarget } }];

const base = $('Extract evidence window').first().json;
const fallbackResults = $('Tavily Search').first()?.json?.results ?? [];
const extracts = $('Tavily Extract').first()?.json?.results ?? [];
const candidate = base.deepCandidate;
const evidence = [];
const seen = new Set();
const isVerifiedSource = (entry) => {
  if (entry.label === 'npm' && entry.title === 'deprecation notice') return true;
  if (!['github-release', 'changelog', 'migration-guide'].includes(entry.label)) return false;
  return String(entry.excerpt ?? '').trim().length >= 80;
};
for (const source of base.canonicalEvidence ?? []) {
  const key = `${source.label}|${source.url}`;
  if (!seen.has(key)) {
    seen.add(key);
    evidence.push(source);
  }
}
for (const extract of extracts.slice(0, 2)) {
  const url = extract.url ?? extract.metadata?.url ?? null;
  if (!url || seen.has(`fallback-search|${url}`)) continue;
  seen.add(`fallback-search|${url}`);
  evidence.push({ packageName: candidate.name, label: 'fallback-search', url, title: extract.title ?? 'fallback source', excerpt: String(extract.raw_content ?? extract.content ?? '').slice(0, 1400), confidence: 'low' });
}
for (const result of fallbackResults.slice(0, 2)) {
  const url = result.url ?? null;
  if (!url || seen.has(`fallback-search|${url}`)) continue;
  seen.add(`fallback-search|${url}`);
  evidence.push({ packageName: candidate.name, label: 'fallback-search', url, title: result.title ?? 'fallback search result', excerpt: String(result.content ?? '').slice(0, 600), confidence: 'low' });
}
const evidenceStatus = evidence.some(isVerifiedSource) ? 'verified' : evidence.length ? 'partial' : 'none';
return [{ json: { ...base, evidence: evidence.slice(0, 8), evidenceStatus } }];

const raw = $input.first().json;
const parsed = raw.output ?? raw;

const prep = $('Score and dedupe evidence').first().json;
const candidate = prep.deepCandidate;

const fallbackBrief = {
  name: candidate.name,
  summary:
    prep.evidenceStatus === 'verified'
      ? `Upgrade ${candidate.currentVersion} -> ${candidate.latestVersion} con evidencia verificada para revisar antes del merge.`
      : prep.evidenceStatus === 'partial'
        ? `Upgrade ${candidate.currentVersion} -> ${candidate.latestVersion} con evidencia parcial; revisa fuentes oficiales antes de aplicar cambios sensibles.`
        : `Upgrade ${candidate.currentVersion} -> ${candidate.latestVersion}. No hubo evidencia suficiente para afirmar breaking changes verificables.`,
  breakingChanges: [],
  testFocus: candidate.deprecated
    ? [
        'Validar rutas criticas que aun usan el paquete deprecated',
        'Aislar impacto de la sustitucion o remocion'
      ]
    : [
        'Smoke test del flujo principal afectado',
        'Verificar build, imports y arranque del proyecto'
      ],
  riskLevel:
    candidate.deprecated || candidate.diffType === 'major'
      ? 'high'
      : candidate.diffType === 'minor'
        ? 'medium'
        : 'low',
  confidence:
    prep.evidenceStatus === 'verified'
      ? 'high'
      : prep.evidenceStatus === 'partial'
        ? 'medium'
        : 'low',
  evidenceStatus: prep.evidenceStatus ?? 'none',
  recommendedActions: candidate.deprecated
    ? [
        'Planificar reemplazo o salida gradual',
        'No expandir nuevas dependencias sobre este paquete'
      ]
    : [
        'Aplicar upgrade en rama corta',
        'Validar test focus antes de mergear'
      ],
  sources: []
};

const allowedSources = new Map();
for (const entry of prep.evidence ?? []) {
  const url = String(entry?.url ?? '');
  const label = String(entry?.label ?? '');
  if (!url || !label) continue;
  if (!allowedSources.has(url)) {
    allowedSources.set(url, {
      packageName: candidate.name,
      label,
      url
    });
  }
}

const merged = { ...fallbackBrief, ...parsed };

const sources = [];
const seen = new Set();

for (const source of [
  ...((merged.sources ?? []).filter(Boolean)),
  ...((prep.evidence ?? []).map((entry) => ({
    packageName: candidate.name,
    label: entry.label,
    url: entry.url
  })))
]) {
  const url = String(source?.url ?? '');
  const canonical = allowedSources.get(url);
  if (!canonical) continue;

  const key = `${canonical.packageName}|${canonical.label}|${canonical.url}`;
  if (seen.has(key)) continue;

  seen.add(key);
  sources.push(canonical);
}

return [
  {
    json: {
      packageBrief: {
        ...merged,
        name: candidate.name,
        sources
      }
    }
  }
];
